import{_ as e,a as d,b as o,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as l,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/ocr.md","filePath":"uk-UA/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"uk-UA/Other/ocr.md"};function h(u,t,g,b,m,P){return l(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR витягує текст із зображень, сканів і скриншотів документів.</p><p>Після розпізнавання можна скопіювати результат, експортувати його як <code>Markdown</code>, <code>PDF</code> або <code>Word</code>, або запакувати кілька форматів разом для завантаження.</p><h2 id="що-може-ocr" tabindex="-1">Що може OCR <a class="header-anchor" href="#що-може-ocr" aria-label="Permalink to &quot;Що може OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Можливість</th><th>Опис</th></tr></thead><tbody><tr><td>Розпізнавання тексту на зображенні</td><td>Витягує текст із зображень, скриншотів і сканів.</td></tr><tr><td>Розпізнавання структури документа</td><td>Краще для таблиць, формул, печаток і змішаних text-image layouts.</td></tr><tr><td>Кілька сервісів</td><td>Підтримує Baidu PaddleOCR, Microsoft Azure Vision і Google Vision.</td></tr><tr><td>Копіювання результатів</td><td>Копіює розпізнаний текст після обробки.</td></tr><tr><td>Експорт файлів</td><td>Експортує <code>Markdown</code>, <code>PDF</code> і <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>Після розпізнавання кількох файлів можна завантажити результати пакетом.</td></tr></tbody></table><h2 id="спочатку-налаштуите-ocr-сервіси" tabindex="-1">Спочатку налаштуйте OCR-сервіси <a class="header-anchor" href="#спочатку-налаштуите-ocr-сервіси" aria-label="Permalink to &quot;Спочатку налаштуйте OCR-сервіси&quot;">​</a></h2><p>Відкрийте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP-геолокація та OCR" loading="lazy"></p><p>Заповніть credentials для сервісів, які хочете використовувати:</p><table tabindex="0"><thead><tr><th>Сервіс</th><th>Що ввести</th><th>Найкраще підходить для</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Рекомендований перший вибір. Добре працює з документами, зображеннями, таблицями та змішаними layout.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> і <code>Azure Vision API Key</code></td><td>Корисно, якщо ви вже користуєтеся хмарними сервісами Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> використовується лише для quota query.</td><td>Корисно, якщо ви користуєтеся Google Cloud.</td></tr></tbody></table><p>Після заповнення credentials збережіть налаштування.</p><p>Для першого тесту можна налаштувати лише один сервіс. Усі три не потрібні.</p><h2 id="налаштування-google-vision" tabindex="-1">Налаштування Google Vision <a class="header-anchor" href="#налаштування-google-vision" aria-label="Permalink to &quot;Налаштування Google Vision&quot;">​</a></h2><p>Налаштування Google має дві частини:</p><table tabindex="0"><thead><tr><th>Мета</th><th>Вимога</th></tr></thead><tbody><tr><td>Використовувати OCR</td><td>Увімкнути <code>Cloud Vision API</code>, потім створити <code>API Key</code>.</td></tr><tr><td>Запитувати usage</td><td>Створити service account, надати <code>Monitoring Viewer</code>, потім завантажити service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key і service account" loading="lazy"></p><h3 id="використання-google-для-ocr" tabindex="-1">Використання Google для OCR <a class="header-anchor" href="#використання-google-для-ocr" aria-label="Permalink to &quot;Використання Google для OCR&quot;">​</a></h3><ol><li>Відкрийте Google Cloud Console.</li><li>Перейдіть до <code>APIs &amp; Services</code>.</li><li>Відкрийте <code>Library</code>, знайдіть <code>Cloud Vision API</code> і ввімкніть його.</li><li>Поверніться до <code>Credentials</code>.</li><li>Створіть <code>API Key</code>.</li><li>Відкрийте API Key і скопіюйте його.</li><li>Вставте його в <code>Google Vision API Key</code> в ImgBed.</li><li>Збережіть.</li></ol><p>Після цього в OCR-діалозі можна вибрати Google Vision.</p><h3 id="запит-usage-google" tabindex="-1">Запит usage Google <a class="header-anchor" href="#запит-usage-google" aria-label="Permalink to &quot;Запит usage Google&quot;">​</a></h3><p>Quota query не потрібен для самого розпізнавання.</p><p>Він лише приблизно показує, скільки викликів Google Vision було використано за останні 30 днів.</p><ol><li>У Google Cloud Console відкрийте <code>IAM &amp; Admin</code>.</li><li>Відкрийте <code>Service Accounts</code>.</li><li>Створіть service account, наприклад <code>vision-monitor</code>.</li><li>Надайте йому роль <code>Monitoring Viewer</code>.</li><li>Відкрийте деталі service account і створіть key.</li><li>Виберіть <code>JSON</code>.</li><li>Завантажте згенерований JSON-файл.</li><li>Поверніться до ImgBed і імпортуйте його в service account <code>JSON</code> (необов&#39;язково).</li><li>Після успішного імпорту натисніть quota query.</li></ol><p>Після імпорту ImgBed показує project name, якому належить service account. Під час запиту usage ImgBed читає Google monitoring data і показує кількість викликів за поточний місяць.</p><p>Коротко:</p><table tabindex="0"><thead><tr><th>Елемент</th><th>Призначення</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Виконує OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Запитує, скільки викликів Google Vision використано.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Дозволяє service account читати usage data.</td></tr></tbody></table><h2 id="отримання-baidu-paddleocr-token" tabindex="-1">Отримання Baidu PaddleOCR Token <a class="header-anchor" href="#отримання-baidu-paddleocr-token" aria-label="Permalink to &quot;Отримання Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR потребує access token.</p><p><img src="'+d+'" alt="Отримання PaddleOCR token" loading="lazy"></p><p>Відкрийте вікно виклику <code>API</code> на сторінці Baidu PaddleOCR, натисніть отримання token і скопіюйте його.</p><p>Поверніться до ImgBed, вставте його в <code>PaddleOCR Token</code> і збережіть.</p><h2 id="запуск-розпізнавання" tabindex="-1">Запуск розпізнавання <a class="header-anchor" href="#запуск-розпізнавання" aria-label="Permalink to &quot;Запуск розпізнавання&quot;">​</a></h2><p>У File Management виберіть зображення або скриншот документа й натисніть <code>OCR</code>.</p><p><img src="'+o+'" alt="OCR recognition" loading="lazy"></p><p>У діалозі виберіть service і model.</p><p>Поширені PaddleOCR models:</p><table tabindex="0"><thead><tr><th>Model</th><th>Найкраще підходить для</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Рекомендовано типово. Добре для документів, таблиць, формул, печаток і змішаних layout.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Прості зображення, звичайний текст і легке розпізнавання.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Багатомовні, складні зображення та chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Складніші сторінки документів і відновлення layout.</td></tr></tbody></table><p>Якщо не впевнені, почніть із <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Опис</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Використовуйте, коли зображення повернуте або перекошене.</td></tr><tr><td>Document flattening</td><td>Для сфотографованих документів із вигином або нахилом.</td></tr><tr><td>Layout detection</td><td>Коли потрібно зберегти headings, paragraphs, tables і структуру зображень.</td></tr><tr><td>Chart recognition</td><td>Коли зображення містить charts або складні структури.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Робить експортований Markdown зручнішим для читання.</td></tr></tbody></table><p>Для звичайних скриншотів залишайте мінімум опцій. Для сканів документів вмикайте більше document-related options.</p><h2 id="перегляд-результатів" tabindex="-1">Перегляд результатів <a class="header-anchor" href="#перегляд-результатів" aria-label="Permalink to &quot;Перегляд результатів&quot;">​</a></h2><p>Після завершення розпізнавання діалог показує результат.</p><p>Його можна скопіювати напряму або вибрати формати експорту.</p><p><img src="'+a+'" alt="PDF recognition" loading="lazy"></p><p>Для сторінок документів експортований <code>PDF</code> може зберігати вигляд сторінки й водночас залишати текст придатним для пошуку. Це зручно для архівування сканів і подальшого пошуку вмісту.</p><h2 id="вибір-формату-експорту" tabindex="-1">Вибір формату експорту <a class="header-anchor" href="#вибір-формату-експорту" aria-label="Permalink to &quot;Вибір формату експорту&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Формат</th><th>Найкраще для</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Нотатки, документаційні системи й подальше редагування.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Збереження вигляду сторінки та результатів сканованих документів.</td></tr><tr><td><code>Word (.docx)</code></td><td>Подальше редагування layout, зміна тексту й передача іншим.</td></tr><tr><td>Export all</td><td>Зберігає кілька форматів і оригінальне зображення, підходить для важливих архівів.</td></tr></tbody></table><p>Якщо потрібен тільки текст, експортуйте Markdown.</p><p>Якщо важливий вигляд сторінки, використовуйте PDF або Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Експортовані Word-документи можна відкривати й редагувати в office software.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>Деякі документи містять розпізнані зображення, headings і paragraphs у Word output.</p><p>Якість розпізнавання залежить від чіткості оригіналу, вибору model і складності документа.</p><h2 id="наикращі-типи-фаилів-для-ocr" tabindex="-1">Найкращі типи файлів для OCR <a class="header-anchor" href="#наикращі-типи-фаилів-для-ocr" aria-label="Permalink to &quot;Найкращі типи файлів для OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Тип файлу</th><th>Рекомендація</th></tr></thead><tbody><tr><td>Чіткі скриншоти</td><td>Розпізнавати напряму.</td></tr><tr><td>Скани</td><td>Краще <code>PP-StructureV3</code>.</td></tr><tr><td>Сфотографовані документи</td><td>Увімкнути orientation correction і document flattening.</td></tr><tr><td>Таблиці, формули, печатки</td><td>Краще structured models.</td></tr><tr><td>Прості короткі текстові зображення</td><td><code>PP-OCRv5</code> зазвичай достатньо.</td></tr></tbody></table><p>Чіткіші зображення з рівнішим текстом зазвичай дають кращий результат.</p><h2 id="типові-випадки" tabindex="-1">Типові випадки <a class="header-anchor" href="#типові-випадки" aria-label="Permalink to &quot;Типові випадки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Випадок</th><th>Значення</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Перевірте, чи збережено service token або key.</td></tr><tr><td>Recognition is slow</td><td>Складні документи й великі зображення потребують більше часу.</td></tr><tr><td>Table is incomplete</td><td>Спробуйте structured model.</td></tr><tr><td>Text has mistakes</td><td>Розмиття, відблиски й перекіс збільшують помилки. Спробуйте чіткіше зображення.</td></tr><tr><td>Word output contains many images</td><td>Structured models можуть зберігати частину розпізнаних зображень. Це нормально.</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>Перевірте:</p><ol><li>Service account <code>JSON</code> імпортовано.</li><li>Service account має роль <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> увімкнено для проєкту.</li></ol><p>Якщо потрібен лише OCR, а не usage query, service account JSON можна не використовувати й заповнити тільки <code>Google Vision API Key</code>.</p><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити System Settings</span></span>
<span class="line"><span>-&gt; Відкрити Other Settings</span></span>
<span class="line"><span>-&gt; Заповнити OCR service credentials</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Повернутися до File Management</span></span>
<span class="line"><span>-&gt; Вибрати файл і натиснути OCR</span></span>
<span class="line"><span>-&gt; Вибрати model</span></span>
<span class="line"><span>-&gt; Дочекатися recognition</span></span>
<span class="line"><span>-&gt; Скопіювати результат або експортувати Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const q=c(p,[["render",h]]);export{k as __pageData,q as default};
